import{_ as i,o as a,c as e,ak as l}from"./chunks/framework.CMX7UUIo.js";const d=JSON.parse('{"title":"Kubernetes 存储详解 (PV, PVC, StorageClass)","description":"","frontmatter":{},"headers":[],"relativePath":"k8s-storage.md","filePath":"k8s-storage.md"}'),t={name:"k8s-storage.md"};function n(r,s,h,p,k,o){return a(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="kubernetes-存储详解-pv-pvc-storageclass" tabindex="-1">Kubernetes 存储详解 (PV, PVC, StorageClass) <a class="header-anchor" href="#kubernetes-存储详解-pv-pvc-storageclass" aria-label="Permalink to “Kubernetes 存储详解 (PV, PVC, StorageClass)”">​</a></h1><p>在 Kubernetes 中，存储卷的管理涉及三个核心概念：<strong>PersistentVolume (PV)</strong>、<strong>PersistentVolumeClaim (PVC)</strong> 和 <strong>StorageClass</strong>。</p><hr><h2 id="_1-💾-persistentvolume-pv-持久化卷" tabindex="-1">1. 💾 PersistentVolume (PV) - 持久化卷 <a class="header-anchor" href="#_1-💾-persistentvolume-pv-持久化卷" aria-label="Permalink to “1. 💾 PersistentVolume (PV) - 持久化卷”">​</a></h2><p>PV 是集群中的一块存储，由管理员配置或使用 StorageClass 动态制备。它是集群资源，就像节点（Node）是集群资源一样。</p><ul><li><strong>📦 性质</strong>：集群级资源，不属于任何命名空间（Namespace）。</li><li><strong>⏳ 生命周期</strong>：独立于使用它的 Pod。</li><li><strong>⚙️ 关键参数</strong>： <ul><li><code>capacity</code>: 存储容量。</li><li><code>accessModes</code>: 访问模式（ReadWriteOnce, ReadOnlyMany, ReadWriteMany）。</li><li><code>persistentVolumeReclaimPolicy</code>: 回收策略（Retain, Delete, Recycle）。</li></ul></li></ul><h2 id="_2-📑-persistentvolumeclaim-pvc-持久化卷声明" tabindex="-1">2. 📑 PersistentVolumeClaim (PVC) - 持久化卷声明 <a class="header-anchor" href="#_2-📑-persistentvolumeclaim-pvc-持久化卷声明" aria-label="Permalink to “2. 📑 PersistentVolumeClaim (PVC) - 持久化卷声明”">​</a></h2><p>PVC 是用户对存储的请求。它类似于 Pod，Pod 消耗节点资源，而 PVC 消耗 PV 资源。</p><ul><li><strong>🏷️ 性质</strong>：命名空间级资源。</li><li><strong>🔗 绑定</strong>：PVC 会寻找符合条件的 PV 进行绑定。</li><li><strong>⚙️ 关键参数</strong>： <ul><li><code>accessModes</code>: 必须与 PV 匹配。</li><li><code>resources</code>: 请求的最小存储大小。</li><li><code>storageClassName</code>: 指定绑定的 StorageClass。</li></ul></li></ul><h2 id="_3-🏗️-storageclass-sc-存储类" tabindex="-1">3. 🏗️ StorageClass (SC) - 存储类 <a class="header-anchor" href="#_3-🏗️-storageclass-sc-存储类" aria-label="Permalink to “3. 🏗️ StorageClass (SC) - 存储类”">​</a></h2><p>StorageClass 为管理员提供了一种描述存储“类”的方法。它实现了 <strong>动态制备 (Dynamic Provisioning)</strong>，即在 PVC 请求时自动创建 PV。</p><ul><li><strong>🎯 作用</strong>：避免管理员手动创建大量的 PV。</li><li><strong>⚙️ 关键参数</strong>： <ul><li><code>provisioner</code>: 决定使用哪个卷插件制备 PV。</li><li><code>parameters</code>: 后端存储的特定参数。</li><li><code>reclaimPolicy</code>: 自动创建的 PV 的回收策略。</li></ul></li></ul><h2 id="_4-🔄-三者的关系" tabindex="-1">4. 🔄 三者的关系 <a class="header-anchor" href="#_4-🔄-三者的关系" aria-label="Permalink to “4. 🔄 三者的关系”">​</a></h2><ol><li><strong>StorageClass</strong> 是 PV 的模板。</li><li><strong>PVC</strong> 是用户的需求单。</li><li><strong>PV</strong> 是实际提供的存储资源。</li></ol><p><strong>💡 流程图示：</strong></p><ul><li><strong>静态模式</strong>：管理员手动创建 PV -&gt; 用户创建 PVC -&gt; 绑定。</li><li><strong>动态模式</strong>：用户创建 PVC (指定 SC) -&gt; SC 自动创建 PV -&gt; 绑定。</li></ul><h2 id="_5-🛠️-常用运维命令" tabindex="-1">5. 🛠️ 常用运维命令 <a class="header-anchor" href="#_5-🛠️-常用运维命令" aria-label="Permalink to “5. 🛠️ 常用运维命令”">​</a></h2><h3 id="🔍-查看资源" tabindex="-1">🔍 查看资源 <a class="header-anchor" href="#🔍-查看资源" aria-label="Permalink to “🔍 查看资源”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看所有 PV</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pv</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看特定命名空间的 PVC</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pvc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">namespac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看存储类</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sc</span></span></code></pre></div><h3 id="描述资源详情" tabindex="-1">描述资源详情 <a class="header-anchor" href="#描述资源详情" aria-label="Permalink to “描述资源详情”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pv</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pv-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pvc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pvc-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">namespac</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div>`,21)])])}const c=i(t,[["render",n]]);export{d as __pageData,c as default};
